select

from osg_job_application
where student_id = #{studentId}
  and company_name = #{companyName}
  and position_name = #{positionName}
order by submitted_at desc, application_id desc
limit 1

select

from osg_job_application


        and position_id = #{positionId}


        and student_name like concat('%', #{studentName}, '%')


        and company_name = #{companyName}


        and current_stage = #{currentStage}


        and lead_mentor_id = #{leadMentorId}


        and assign_status = #{assignStatus}


        and coaching_status = #{status}


        and date_format(interview_time, '%Y-%m') = #{month}


        and (
            student_name like concat('%', #{keyword}, '%')
            or company_name like concat('%', #{keyword}, '%')
            or position_name like concat('%', #{keyword}, '%')
        )


order by submitted_at desc, application_id desc

mapper.update:
update osg_job_application
assign_status = #{assignStatus}, coaching_status = #{coachingStatus}, update_by = #{updateBy}, update_time = sysdate(), remark = #{remark},
where application_id = #{applicationId}

update osg_job_application
current_stage = #{currentStage}, interview_time = #{interviewTime}, stage_updated = #{stageUpdated}, update_by = #{updateBy}, update_time = sysdate(), remark = #{remark},
where application_id = #{applicationId}

update osg_job_application
current_stage = #{currentStage}, assign_status = #{assignStatus}, coaching_status = #{coachingStatus}, requested_mentor_count = #{requestedMentorCount}, preferred_mentor_names = #{preferredMentorNames}, remark = #{remark}, update_time = sysdate()
where application_id = #{applicationId}
